SELECT 
    so.*,
    u.real_name as cashier_name,
    m.name as member_name,
    m.card_no
FROM sales_order so
LEFT JOIN sys_user u ON so.cashier_id = u.user_id
LEFT JOIN member_info m ON so.member_id = m.member_id


        AND so.order_id = #{orderId}


        AND so.member_id = #{memberId}


        AND so.cashier_id = #{cashierId}


        AND so.status = #{status}


        AND so.order_time >= #{startDate}


        AND so.order_time <= #{endDate}


ORDER BY so.order_time DESC

SELECT COALESCE(SUM(pay_amount), 0)
FROM sales_order
WHERE order_time >= #{startDate}
  AND order_time <= #{endDate}
  AND status = '已完成'
